// src/app/dashboard/page.tsx
import { Wallet } from "@prisma/client";
import { prisma } from "../../lib/prisma";
import { transferGaji } from "../actions"; // Pastikan file actions.ts sudah kamu buat

export default async function UserDashboard() {
    const wallets = await prisma.wallet.findMany();

    return (
        <main className="p-10 bg-slate-50 min-h-screen">
        <h1 className="text-3xl font-bold mb-6 text-slate-800">Dashboard Keuangan</h1>
        
        {/* 1. Baris Kartu Saldo */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {wallets.map((wallet: Wallet) => (
            <div key={wallet.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start">
                <div>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{wallet.type}</p>
                    <h2 className="text-lg font-bold text-slate-700">{wallet.name}</h2>
                </div>
                <div className={`p-2 rounded-lg ${wallet.type === 'BANK' ? 'bg-blue-100 text-blue-600' : 'bg-purple-100 text-purple-600'}`}>
                    {wallet.type === 'BANK' ? '🏦' : '📱'}
                </div>
                </div>
                <p className="text-3xl mt-6 font-bold text-slate-900">
                <span className="text-sm font-normal text-slate-400 mr-1">Rp</span>
                {wallet.balance.toLocaleString('id-ID')}
                </p>
            </div>
            ))}
        </div>

        {/* 2. TOMBOL BARU: Kita taruh di sini! */}
        <div className="mt-8 p-6 bg-white rounded-xl shadow-md border border-slate-200 inline-block">
            <h3 className="font-bold text-slate-700 mb-4">Aksi Cepat:</h3>
            <form action={transferGaji}>
            <button
                type="submit"
                className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-6 rounded-lg transition-colors shadow-lg"
            >
                💸 Pindahkan Rp 1.000.000 (Bank = Gopay)
            </button>
            </form>
        </div>

        {/* 3. Kotak Info */}
        <div className="mt-10 p-6 bg-blue-50 border border-blue-100 rounded-lg">
            <p className="text-blue-700 font-medium">
            💡 Data di atas diambil langsung dari PostgreSQL yang baru saja kamu isi lewat seed!
            </p>
        </div>
        </main>
    );
}